            font-weight: 700;
            color: #ffd700;
            text-shadow: 0 0 12px #ffbb00;
            margin: 10px 0;
        }

        .desc {
            font-size: 0.9rem;
            color: #b0d0e0;
            margin-bottom: 20px;
            line-height: 1.4;
        }

